-- Apex Advantage Member Portal — Premium content server-side enforcement (v5)
--
-- Phase 1 of the launch-readiness hardening pass. This migration:
--   1. Creates tables for the Checkride Prep content (DPE questions,
--      quick-reference sheets, lessons) that today lives as plain-text
--      JS literals in site/portal.js — a public static file readable by
--      anyone without logging in or paying. Moving it here + gating all
--      reads through the get-premium-content Edge Function (which checks
--      profiles.checkride_prep_unlocked before returning anything) is
--      the actual fix for that exposure; the RLS below additionally
--      blocks any direct client query of these tables regardless.
--   2. Seeds those tables with the exact content extracted from
--      site/portal.js (72 DPE questions, 9 categories, 7 quick-reference
--      sheets, 2 lessons) — see the extraction script noted below if
--      this content is ever edited again before portal.js's copies are
--      deleted.
--   3. Closes a self-moderation gap found during the security audit:
--      portal_referrals, portal_testimonials, and
--      portal_question_discussions all use a single `for all` RLS
--      policy scoped only to `auth.uid() = owner`, which does not
--      restrict which *columns* a user can change — so an authenticated
--      user could UPDATE their own row's `status`/`answer` columns
--      directly (e.g. self-approve a testimonial, or write a fake
--      "answer" to their own Ask Andrew question and mark it answered,
--      which immediately becomes publicly visible via the existing
--      "any authenticated user can view answered/approved" policies).
--      Triggers below lock those specific columns to admin-only writes
--      without changing the existing policies or app behavior otherwise.
--
-- Run this in the Supabase SQL editor, after supabase-portal-schema-v2,
-- v3, and portal/supabase-portal-schema-v4.sql.
--
-- NOT covered by this migration (see LAUNCH_READINESS_REPORT.md):
-- ground_sessions / ground_registrations have no CREATE TABLE in any
-- committed SQL file (created directly in the Supabase dashboard) and
-- their current RLS state cannot be verified from this repo. Given both
-- tables are reachable from public, unauthenticated routes
-- (/ground-schedule registration form, /attend/:type/:token check-in)
-- and now hold payment data (stripe_session_id, amount_cents,
-- payment_status) and PII (name, email), this needs a manual check in
-- the Supabase dashboard before launch — see the report for exactly
-- what to check and the policies to apply once current state is known.

-- ─────────────────────────────────────────────────────────────────
-- 1. Premium content tables — admin-only direct access.
-- Real reads only ever happen through get-premium-content (service
-- role, gated on checkride_prep_unlocked). The admin-select policy
-- exists for the future content-management UI (Phase 4).
-- ─────────────────────────────────────────────────────────────────
create table public.dpe_categories (
  id           text primary key,
  label        text not null,
  section_label text not null,
  intro        text not null,
  sort_order   integer not null default 0
);
alter table public.dpe_categories enable row level security;
create policy "Admins can view all DPE categories"
  on public.dpe_categories for select
  using (exists (select 1 from public.profiles where id = auth.uid() and role = 'admin'));

create table public.dpe_questions (
  id                       text primary key,
  category                 text not null references public.dpe_categories(id),
  question                 text not null,
  model_answer             text not null,
  common_mistakes          text,
  dpe_evaluating           text,
  acs_reference            text,
  real_world_application   text,
  is_scenario              boolean not null default false,
  scenario_order           integer,
  sort_order               integer not null default 0,
  created_at               timestamptz not null default now()
);
alter table public.dpe_questions enable row level security;
create policy "Admins can view all DPE questions"
  on public.dpe_questions for select
  using (exists (select 1 from public.profiles where id = auth.uid() and role = 'admin'));

create table public.quick_reference_sheets (
  id         text primary key,
  title      text not null,
  subtitle   text not null,
  rows       jsonb not null,
  sort_order integer not null default 0
);
alter table public.quick_reference_sheets enable row level security;
create policy "Admins can view all quick reference sheets"
  on public.quick_reference_sheets for select
  using (exists (select 1 from public.profiles where id = auth.uid() and role = 'admin'));

create table public.portal_lessons (
  id         text primary key,
  title      text not null,
  meta       text not null,
  parts      jsonb not null,
  sort_order integer not null default 0
);
alter table public.portal_lessons enable row level security;
create policy "Admins can view all portal lessons"
  on public.portal_lessons for select
  using (exists (select 1 from public.profiles where id = auth.uid() and role = 'admin'));

-- ─────────────────────────────────────────────────────────────────
-- 2. RLS hardening — close the self-moderation gap on 3 tables.
-- Each trigger silently reverts admin-controlled columns back to their
-- previous value whenever the actor isn't an admin, regardless of what
-- the UPDATE statement tried to set them to. Everything else about
-- these tables (insert, select policies, non-protected-column updates)
-- is unchanged.
-- ─────────────────────────────────────────────────────────────────
create or replace function public.lock_referral_status()
returns trigger language plpgsql security definer set search_path = public as $$
begin
  if not exists (select 1 from public.profiles where id = auth.uid() and role = 'admin') then
    new.status := old.status;
  end if;
  return new;
end;
$$;
drop trigger if exists trg_lock_referral_status on public.portal_referrals;
create trigger trg_lock_referral_status
  before update on public.portal_referrals
  for each row execute procedure public.lock_referral_status();

create or replace function public.lock_testimonial_status()
returns trigger language plpgsql security definer set search_path = public as $$
begin
  if not exists (select 1 from public.profiles where id = auth.uid() and role = 'admin') then
    new.status := old.status;
  end if;
  return new;
end;
$$;
drop trigger if exists trg_lock_testimonial_status on public.portal_testimonials;
create trigger trg_lock_testimonial_status
  before update on public.portal_testimonials
  for each row execute procedure public.lock_testimonial_status();

create or replace function public.lock_question_discussion_moderation()
returns trigger language plpgsql security definer set search_path = public as $$
begin
  if not exists (select 1 from public.profiles where id = auth.uid() and role = 'admin') then
    new.status := old.status;
    new.answer := old.answer;
    new.answered_at := old.answered_at;
  end if;
  return new;
end;
$$;
drop trigger if exists trg_lock_question_discussion_moderation on public.portal_question_discussions;
create trigger trg_lock_question_discussion_moderation
  before update on public.portal_question_discussions
  for each row execute procedure public.lock_question_discussion_moderation();

-- ─────────────────────────────────────────────────────────────────
-- 3. Seed data — extracted verbatim from site/portal.js
-- (DPE_DATA, CATEGORY_META, QUICK_REF, FRAMEWORK_LESSON,
-- CHECKRIDE_DAY_LESSON). Content is unchanged from what's live today;
-- this only changes where it's stored and how it's served.
-- ─────────────────────────────────────────────────────────────────
-- Auto-generated seed data extracted from site/portal.js — DO NOT hand-edit.
-- Regenerate via the extraction script if the source content ever changes before this migration ships.

insert into public.dpe_categories (id, label, section_label, intro, sort_order) values
  ('eligibility', 'Eligibility & Documents', 'Section 2', 'Every oral exam opens here — documents, certificates, and eligibility. It''s the lowest-difficulty section of the exam in terms of content, and also the section where avoidable, embarrassing mistakes (an expired medical, a missing endorsement) do the most unnecessary damage to an applicant''s confidence and first impression.', 0),
  ('airworthiness', 'Airworthiness', 'Section 3', 'Airworthiness questions test whether you understand your responsibility, as PIC, to determine whether the specific aircraft you''re about to fly is legal and safe — not just whether you can recite an inspection schedule from memory.', 1),
  ('privileges', 'Privileges & Limitations', 'Section 4', 'This section tests whether you know exactly what a Private Pilot Certificate allows you to do — and just as importantly, what it doesn''t. Precision matters here: examiners often probe the edges of a privilege, not just its general existence.', 2),
  ('airspace', 'Airspace', 'Section 5', 'Airspace questions test whether you can instantly recall dimensions, entry requirements, and weather minimums — chart-independent, from memory — since real flight planning happens before you ever pull up a chart in the airplane.', 3),
  ('weather', 'Weather', 'Section 6', 'Weather questions test two things at once: can you decode the raw products, and can you translate that decoded information into a real go/no-go decision. Both matter — a DPE cares less about your ability to define a term than your ability to use it.', 4),
  ('performance', 'Performance & W&B', 'Section 7', 'This section tests whether you can turn published aircraft numbers into an actual go/no-go decision for a specific day, specific loading, and specific runway — not just whether you can read a chart in isolation.', 5),
  ('aeromedical', 'Aeromedical Factors', 'Section 8', 'This section blends physiology with self-awareness. It''s the one part of the exam that tests judgment about yourself, not just the airplane or the airspace — and it''s a section many applicants under-prepare because it feels less technical than the rest.', 6),
  ('crosscountry', 'Cross-Country Planning', 'Section 9', 'Cross-country planning ties together nearly everything else in this guide — airspace, weather, performance, and regulations — into a single, complete flight plan. This is often where the oral exam''s scenario-based structure becomes most obvious.', 7),
  ('emergency', 'Emergency Operations', 'Section 10', 'Emergency questions test whether calm, procedural thinking is already built into your instincts — examiners are listening for structured response, not dramatic language. This section rewards the pilot who sounds like they''ve genuinely rehearsed this, not just read about it.', 8);

insert into public.dpe_questions (id, category, question, model_answer, common_mistakes, dpe_evaluating, acs_reference, real_world_application, is_scenario, scenario_order, sort_order) values
  ('elig-1', 'eligibility', 'What are the eligibility requirements to apply for a Private Pilot Certificate?', 'You must be at least 17 years old, be able to read, speak, write, and understand English, and hold at least a third-class medical certificate (or qualify under BasicMed for certain operations), along with the required aeronautical experience and endorsements.', 'Listing only age and medical requirements, omitting the English-language proficiency requirement or required endorsements.', 'Whether you can state a complete, accurate eligibility list — not just the parts that come to mind first.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'This is almost always the opening question of an oral exam — a clean, complete answer sets a confident tone for everything that follows.', false, null, 0),
  ('elig-2', 'eligibility', 'What is the difference between a student pilot certificate and a medical certificate?', 'The student pilot certificate authorizes you to act as pilot in command while training and solo; the medical certificate establishes your medical fitness to fly. They serve different purposes, even though newer applicants often receive them as a single combined document.', 'Treating the two as interchangeable, or assuming one document covers both functions.', 'Whether you understand the distinct legal purpose of each document, not just that you possess them.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'If your medical lapses but your student certificate is still valid, you are no longer legal to act as PIC — understanding why matters, not just knowing you need both.', false, null, 1),
  ('elig-3', 'eligibility', 'What are the three classes of medical certificates, and what is BasicMed?', 'First class (for ATP privileges), second class (for commercial privileges), and third class (for private/recreational privileges), each with different duration and examination requirements. BasicMed is an alternative to holding a traditional medical certificate for certain private pilot operations, requiring a physician''s exam and an online medical education course rather than an FAA medical exam.', 'Describing BasicMed as a full exemption from medical oversight rather than a defined alternative pathway with its own requirements and limitations.', 'Whether you understand both pathways well enough to explain which one applies to your specific situation.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Many private pilots fly indefinitely under BasicMed after their last FAA medical — know your own certificate''s expiration and which pathway you''re currently operating under.', false, null, 2),
  ('elig-4', 'eligibility', 'What endorsements are required before you can take your Private Pilot checkride?', 'Endorsements confirming you have received and logged the required aeronautical knowledge and flight training, that you are prepared for the required knowledge test and have satisfactory knowledge of any missed subject areas, and a final endorsement that you have received training and are prepared for the practical test.', 'Naming only the pre-solo endorsement, or forgetting the knowledge-test-related endorsements.', 'Whether your logbook and endorsement paperwork are actually complete — this is often verified by physically reviewing your logbook.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'A DPE will check these endorsements against your logbook before the oral exam even begins — incomplete paperwork can delay or cancel a checkride entirely.', false, null, 3),
  ('elig-5', 'eligibility', 'What is IACRA, and what role does it play in the certification process?', 'IACRA (Integrated Airman Certification and Rating Application) is the FAA''s online system for applying for pilot certificates and ratings, and for scheduling the Knowledge Test. Your application must be completed and often digitally signed by your instructor before your checkride.', 'Being unfamiliar with how to actually navigate or complete an IACRA application, since applicants often have an instructor complete this step for them.', 'Basic operational familiarity with the certification process itself, not just the flying content.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Practice logging into and navigating your own IACRA account before checkride day — paperwork problems on the day of your exam are entirely avoidable.', false, null, 4),
  ('elig-6', 'eligibility', 'What personal identification and documents must you bring to your checkride?', 'A government-issued photo ID, your student pilot certificate (or combined certificate/medical), your completed IACRA application (Form 8710-1), your logbook with all required endorsements, and your Knowledge Test Report.', 'Forgetting the Knowledge Test Report specifically, or bringing an expired photo ID.', 'Basic checkride-day readiness and attention to logistics — a low-difficulty but high-consequence area to get wrong.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Build a physical checklist the week before your checkride and verify every item the night before — don''t rely on memory on exam morning.', false, null, 5),
  ('elig-7', 'eligibility', 'What must be logged in a pilot logbook?', 'Training and aeronautical experience used to meet certificate or rating requirements, and information required to show recency of experience — including date, aircraft, route, flight time, conditions of flight, and type of pilot experience (dual, solo, PIC, cross-country, night, instrument).', 'Believing every flight must be logged — only flights used to meet requirements or demonstrate recency are legally required, though most pilots log all flight time as good practice.', 'Whether you understand what logging is legally required versus simply customary.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Be ready to walk a DPE through your own logbook and explain how specific entries satisfy specific aeronautical experience requirements — not just that the hours exist.', false, null, 6),
  ('elig-8', 'eligibility', 'What is a Knowledge Test Report, and how does it connect to the ACS?', 'It''s the report issued after completing the FAA Knowledge Test, listing ACS codes for any subject areas missed. Those codes map directly to specific ACS Tasks, which you and your instructor should use to focus review before the checkride.', 'Not knowing how to interpret the ACS codes on your own report, or not having reviewed missed areas before the oral exam.', 'Whether you took your own knowledge gaps seriously and can speak to how you addressed them.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Expect a DPE to specifically ask about any ACS codes you missed on your Knowledge Test — have a genuine, prepared answer, not a vague one.', false, null, 7),
  ('aw-1', 'airworthiness', 'What does ARROW stand for, and why does it matter?', 'ARROW is the required-documents mnemonic: Airworthiness certificate, Registration, Radio station license (only required for certain international operations), Operating limitations (POH/AFM or placards), and Weight and balance data. These documents must be aboard the aircraft for flight.', 'Forgetting that the radio station license is generally not required for domestic U.S. operations, or omitting weight and balance data.', 'Whether you can recite this from memory and correctly explain any nuance (like the radio license exception), not just the acronym alone.', 'Area of Operation I, Task B — Airworthiness Requirements (Knowledge).', 'Be ready to physically locate each ARROW document in your training aircraft during the oral exam — DPEs frequently ask you to produce them, not just name them.', false, null, 8),
  ('aw-2', 'airworthiness', 'What makes an aircraft airworthy?', 'An aircraft is airworthy when it conforms to its type certificate (or approved alterations) and is in a condition for safe operation. Both conditions must be true — an aircraft can conform to its type design but still be unsafe due to damage or missing maintenance.', 'Defining airworthiness only in terms of having a current annual inspection, which is necessary but not sufficient on its own.', 'Whether you understand this as a two-part legal definition, not a single checklist item.', 'Area of Operation I, Task B — Airworthiness Requirements (Knowledge).', 'As PIC, you are legally responsible for determining airworthiness before every flight — this isn''t just the mechanic''s job.', false, null, 9),
  ('aw-3', 'airworthiness', 'What inspections does an aircraft need to remain legal for flight?', 'An annual inspection (every 12 calendar months), a 100-hour inspection (if used for hire or flight instruction for hire), a transponder and altimeter/pitot-static system check (every 24 calendar months, for operations requiring them), and an ELT inspection (every 12 calendar months, with battery replacement per manufacturer requirements or after one hour of cumulative use).', 'Confusing the 24-month transponder/altimeter cycle with the 12-month annual cycle, or forgetting the ELT battery replacement rule.', 'Whether you can locate the actual due dates for these inspections in your own aircraft''s logbooks, not just recite the intervals.', 'Area of Operation I, Task B — Airworthiness Requirements (Knowledge).', 'Practice pulling up your training aircraft''s actual maintenance logs and finding each inspection''s due date before your checkride — this is a very commonly tested practical skill.', false, null, 10),
  ('aw-4', 'airworthiness', 'What is required for an annual inspection, and who can perform it?', 'Every aircraft must undergo an annual inspection within the preceding 12 calendar months, performed by an FAA-certificated Airframe and Powerplant (A&P) mechanic holding an Inspection Authorization (IA).', 'Believing any A&P mechanic can sign off an annual inspection — the Inspection Authorization is a specific, additional certification.', 'Precision in distinguishing an A&P mechanic''s general privileges from an IA holder''s specific annual-inspection authority.', 'Area of Operation I, Task B — Airworthiness Requirements (Knowledge).', 'If you ever purchase or manage an aircraft, knowing this distinction matters for scheduling maintenance with the right qualified person.', false, null, 11),
  ('aw-5', 'airworthiness', 'When is a 100-hour inspection required, and what happens if it''s exceeded?', 'A 100-hour inspection is required for aircraft used to carry passengers for hire or used for flight instruction for hire. If the 100-hour limit is exceeded, the aircraft may be flown up to 10 additional hours to reach a location where the inspection can be performed, but those extra hours count toward the next 100-hour interval.', 'Assuming the 10-hour overflight allowance is ''free'' time rather than time that still counts against the next inspection cycle.', 'Whether you understand this as a limited operational allowance, not a loophole.', 'Area of Operation I, Task B — Airworthiness Requirements (Knowledge).', 'This rule is most relevant to flight school and rental aircraft — understand it even if you don''t own the aircraft you train in.', false, null, 12),
  ('aw-6', 'airworthiness', 'What is Airworthiness Directive (AD) compliance, and why does it matter?', 'An Airworthiness Directive is a legally enforceable FAA regulation addressing an unsafe condition in a specific aircraft, engine, or component. Compliance is mandatory, and AD compliance is tracked and documented in the aircraft''s maintenance records.', 'Confusing an AD (mandatory) with a Service Bulletin (often optional, manufacturer-issued guidance).', 'Whether you understand ADs as a distinct, non-negotiable category of maintenance requirement.', 'Area of Operation I, Task B — Airworthiness Requirements (Knowledge).', 'A DPE may ask you to find evidence of AD compliance in the aircraft''s logbooks — know generally where and how this is documented.', false, null, 13),
  ('aw-7', 'airworthiness', 'What is the process under 14 CFR 91.213 when equipment is inoperative?', 'First check if the aircraft has an approved Minimum Equipment List (MEL) — if so, follow it. If there''s no MEL, determine whether the inoperative item is required by the type certification, by 91.205, by an Airworthiness Directive, or is otherwise flight-critical; if not required by any of those, it may be removed or deactivated and placarded inoperative, or the flight may proceed if none of those conditions apply.', 'Skipping the MEL question first, or forgetting that inoperative equipment not covered by any required list may still need to be deactivated and placarded, not simply ignored.', 'Whether you can walk through this multi-step decision logic in the correct order, live, without skipping a step.', 'Area of Operation I, Task B — Airworthiness Requirements (Knowledge, Risk Management).', 'This is one of the most commonly tested, multi-step regulatory questions on the exam — practice walking through it out loud until the sequence is automatic.', false, null, 14),
  ('aw-8', 'airworthiness', 'What are your responsibilities as PIC if you discover a discrepancy during preflight?', 'You must determine whether the discrepancy affects airworthiness or required equipment, apply the 91.213 process if equipment is involved, and document or communicate the discrepancy appropriately — and ultimately, decide not to fly if you cannot establish the aircraft is airworthy.', 'Treating a discrepancy as automatically disqualifying without applying the actual regulatory decision process, or the opposite — dismissing a real discrepancy too quickly.', 'Sound risk management judgment, not just regulatory recall — this element blends Knowledge with Risk Management explicitly.', 'Area of Operation I, Task B — Airworthiness Requirements (Risk Management).', 'This exact judgment call — fly or don''t fly, based on a real preflight discrepancy — is one you''ll actually face as a certificated pilot, likely more than once.', false, null, 15),
  ('priv-1', 'privileges', 'What is required to remain current to carry passengers?', 'Within the preceding 24 calendar months, you must complete a flight review (or equivalent) with an authorized instructor. To carry passengers, you must also have made three takeoffs and three landings in the preceding 90 days in an aircraft of the same category and class (and type, if required); for night currency, those takeoffs and landings must be to a full stop, between one hour after sunset and one hour before sunrise.', 'Forgetting the distinction between day currency (touch-and-go acceptable) and night currency (full stop required), or confusing the 24-month flight review cycle with the 90-day passenger currency cycle.', 'Precision across two different currency timeframes that are frequently confused with each other.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Track your own three-takeoffs-and-landings currency actively — many pilots are surprised to find themselves not current to carry a passenger simply from infrequent flying.', false, null, 16),
  ('priv-2', 'privileges', 'What is a flight review, and when is it required?', 'A flight review is a minimum one-hour flight and one-hour ground review with an authorized instructor, required within the preceding 24 calendar months to act as PIC. It is not a test with a pass/fail outcome — it''s a review, and the instructor endorses your logbook upon satisfactory completion.', 'Describing the flight review as a retest of checkride-level maneuvers, or believing it can be ''failed'' in the same sense as a practical test.', 'Correct understanding of the flight review''s actual regulatory purpose and tone.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Many activities (an additional certificate or rating, certain phase of an FAA safety program) can substitute for a flight review — know that flexibility exists.', false, null, 17),
  ('priv-3', 'privileges', 'What are the requirements and limitations of flying under BasicMed?', 'You must have held a valid medical certificate at some point after July 14, 2006, complete a physician''s comprehensive medical exam using the FAA''s checklist, and complete a free online medical education course. Under BasicMed, you''re limited to aircraft with 6 or fewer seats and 6,000 lbs or less max takeoff weight, flying no higher than 18,000 feet MSL, no faster than 250 knots, and not for compensation or hire (with limited exceptions).', 'Forgetting the aircraft weight/seat limitations, or believing BasicMed has no altitude or airspeed limits.', 'Detailed, specific knowledge of BasicMed''s actual limitations, not just that the pathway exists.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'If you plan to fly under BasicMed long-term, know these limits well — they directly affect what aircraft and altitudes are available to you.', false, null, 18),
  ('priv-4', 'privileges', 'Can a private pilot ever receive compensation for flying?', 'Generally no — a private pilot may not act as PIC for compensation or hire. Limited exceptions exist, such as sharing operating expenses pro rata with passengers on a flight where the pilot has a common purpose, or certain charitable/search-and-rescue flights under specific conditions.', 'Stating an absolute ''never'' without acknowledging the pro rata share exception, or misapplying the exception to a flight that doesn''t actually qualify.', 'Whether you understand this as a general prohibition with narrow, specific exceptions — not an absolute rule or a loophole.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'The pro rata rule comes up constantly in real private flying — splitting fuel costs with friends on a trip is common, and knowing the rule precisely keeps that legal.', false, null, 19),
  ('priv-5', 'privileges', 'What is the pro rata share rule, and how does it work?', 'A private pilot may share the operating expenses of a flight (fuel, oil, airport expenses, rental fees) with passengers, as long as the pilot pays at least an equal, pro rata share of those costs, and the pilot has their own reason for making the flight (not merely to earn compensation by carrying passengers).', 'Believing passengers can cover the entire cost of the flight, or that the pilot can pay less than an equal share.', 'Precise understanding of both conditions — pro rata payment AND a common purpose — not just one.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'This is the regulation that makes it legal to split costs on a weekend trip with friends — know it precisely before you rely on it.', false, null, 20),
  ('priv-6', 'privileges', 'What preventive maintenance can a private pilot legally perform on their own aircraft?', 'A list of specific, simple maintenance tasks defined in the FARs — such as servicing landing gear wheel bearings, replacing safety wire, servicing batteries, and changing tires — may be performed by a certificated private pilot on an aircraft they own or operate, with the work properly logged.', 'Believing any minor maintenance task qualifies, rather than only the specific items listed in the regulation.', 'Awareness that this is a defined, limited list — not general permission to perform maintenance.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'Relevant primarily to aircraft owners — know that this privilege exists and that it must be properly logged, even if you don''t currently own an aircraft.', false, null, 21),
  ('priv-7', 'privileges', 'What flight time can a private pilot log as pilot in command?', 'You may log PIC time when you are the sole manipulator of the controls of an aircraft for which you are rated, or when you are the sole occupant, or when acting as PIC under the regulations even if not sole manipulator (such as certain instructional or safety pilot scenarios).', 'Believing PIC time can only be logged when you are legally the PIC of record for the flight, conflating ''logging PIC time'' with ''acting as PIC.''', 'Whether you understand that logging PIC time and acting as PIC are related but legally distinct concepts.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'This distinction matters most once you begin flying with other pilots or working toward additional certificates — log time accurately from the start.', false, null, 22),
  ('priv-8', 'privileges', 'What is the pilot in command''s ultimate authority and responsibility under 14 CFR 91.3?', 'The PIC is directly responsible for, and is the final authority as to, the operation of the aircraft. In an in-flight emergency requiring immediate action, the PIC may deviate from any rule to the extent required to meet that emergency.', 'Forgetting the emergency deviation authority, or overstating it as unlimited rather than limited to what the emergency actually requires.', 'Whether you understand both halves of 91.3 — the general authority and the specific emergency exception.', 'Area of Operation I, Task A — Pilot Qualifications (Knowledge).', 'This regulation is the foundation of everything else in this guide — as PIC, the final call is always yours, and so is the responsibility.', false, null, 23),
  ('asp-1', 'airspace', 'What are the basic characteristics of Class A airspace?', 'Class A airspace extends from 18,000 feet MSL up to and including FL600, covers the entire continental U.S., and requires operation under IFR with an appropriately rated pilot and equipped aircraft. VFR flight is not permitted in Class A airspace.', 'Believing VFR flight is permitted with special clearance — it is not permitted at all in Class A.', 'Whether you understand Class A as an absolute IFR-only environment, with no VFR exception.', 'Area of Operation III, Task A — Airspace (Knowledge).', 'As a private pilot flying VFR, Class A simply defines your operational ceiling — you''ll plan cross-countries to stay well below it.', false, null, 24),
  ('asp-2', 'airspace', 'What are the entry requirements for Class B airspace?', 'You need an explicit ATC clearance to enter Class B airspace (not just two-way radio contact), a Mode C transponder with ADS-B Out where required, and for a private pilot, no additional certificate restrictions apply, though student pilots have specific training and airport restrictions.', 'Confusing ''established two-way radio communication'' (the Class C/D standard) with the stricter ''explicit clearance'' requirement for Class B.', 'Precision distinguishing Class B''s clearance requirement from Class C/D''s communication requirement.', 'Area of Operation III, Task A — Airspace (Knowledge).', 'Misunderstanding this distinction is a real operational risk — entering Class B without an actual clearance, believing radio contact alone was sufficient, is a genuine pilot deviation.', false, null, 25),
  ('asp-3', 'airspace', 'What is required to operate in Class C airspace?', 'Two-way radio communication must be established with ATC before entering (not necessarily a clearance), and the aircraft must have an operating Mode C transponder with ADS-B Out where required. Class C typically has a surface area and an outer shelf with different dimensions.', 'Believing a clearance is required, as in Class B, rather than simply established two-way communication.', 'Correct, precise use of ''established two-way communication'' as the specific legal standard.', 'Area of Operation III, Task A — Airspace (Knowledge).', 'Know exactly what ''established communication'' means in practice — ATC using your call sign back to you, not just you calling in.', false, null, 26),
  ('asp-4', 'airspace', 'What is required to operate in Class D airspace?', 'Two-way radio communication must be established with the control tower before entering. Class D airspace typically extends from the surface up to 2,500 feet AGL around an airport with an operating control tower.', 'Assuming Class D always requires a transponder — equipment requirements depend on surrounding airspace, not Class D status alone.', 'Whether you distinguish Class D''s communication requirement from any separate equipment requirement that might apply based on nearby airspace.', 'Area of Operation III, Task A — Airspace (Knowledge).', 'Class D airspace reverts to Class E or G when the tower is closed — know how to check tower operating hours during flight planning.', false, null, 27),
  ('asp-5', 'airspace', 'What are the VFR weather minimums in Class E airspace below 10,000 feet MSL?', '3 statute miles visibility, and cloud clearance of 500 feet below, 1,000 feet above, and 2,000 feet horizontal from clouds.', 'Confusing these minimums with the higher minimums required above 10,000 feet MSL (5 miles visibility, 1,000 below/above, 1 mile horizontal).', 'Whether these specific numbers are truly memorized, not looked up — this is treated as baseline private pilot knowledge.', 'Area of Operation III, Task A — Airspace (Knowledge).', 'These are the minimums you''ll use on the overwhelming majority of real VFR cross-country flights — they should be completely automatic.', false, null, 28),
  ('asp-6', 'airspace', 'What defines Class G airspace, and what are its weather minimums?', 'Class G is uncontrolled airspace, generally from the surface up to the base of the overlying Class E airspace. Weather minimums vary by altitude and day/night: below 1,200 feet AGL during the day, minimums are 1 statute mile visibility and clear of clouds; other Class G minimums scale up with altitude and at night.', 'Assuming Class G has no weather minimums at all, or applying the same minimums regardless of altitude and time of day.', 'Whether you know Class G''s minimums genuinely vary by altitude and day/night, not just a single blanket rule.', 'Area of Operation III, Task A — Airspace (Knowledge).', 'Class G''s minimal requirements are exactly why ''uncontrolled'' doesn''t mean ''unregulated'' — apply real judgment even where the legal bar is lower.', false, null, 29),
  ('asp-7', 'airspace', 'What is special use airspace, and how do you check its status?', 'Special use airspace includes restricted areas, prohibited areas, warning areas, military operations areas (MOAs), and alert areas — each with different entry rules. Status (active/inactive) can be checked via a flight briefing, NOTAMs, or overlays in an EFB like ForeFlight or Garmin Pilot.', 'Treating all special use airspace the same — prohibited areas are never enterable, while MOAs may be legally transited by VFR traffic with caution even when active.', 'Whether you distinguish between the different categories and their actual entry rules, not just that they all sound restrictive.', 'Area of Operation III, Task A — Airspace (Knowledge, Risk Management).', 'Always check special use airspace status during real flight planning, not just note that it exists on the chart — an inactive MOA changes your routing decision entirely.', false, null, 30),
  ('asp-8', 'airspace', 'What is a TFR, and how do you check for one before a flight?', 'A Temporary Flight Restriction is a short-term airspace restriction, often issued for security, disaster response, or VIP movement. Check for active TFRs via TFR.faa.gov, a standard weather briefing, or your EFB''s NOTAM/TFR overlay, as part of routine flight planning for every flight.', 'Checking for TFRs only when flying near a major city or event, rather than as a standard part of every flight''s preflight planning.', 'Whether TFR checking is built into your habitual flight-planning process, not treated as an occasional special step.', 'Area of Operation III, Task A — Airspace (Knowledge, Risk Management).', 'TFRs can appear with little notice — checking immediately before every flight, not just during initial planning days earlier, is the only reliable habit.', false, null, 31),
  ('wx-1', 'weather', 'How do you decode a METAR?', 'A METAR reports, in order: station identifier, date/time, wind, visibility, weather/obstructions, sky condition, temperature/dew point, altimeter setting, and remarks. Practice decoding full strings, in order, without a reference card.', 'Skipping straight to sky condition and altimeter, ignoring the remarks section, which often contains operationally important information.', 'Whether you can decode a real METAR live, cold, without hesitation — this is one of the most commonly tested live-decoding skills.', 'Area of Operation II, Task A — Weather Information (Knowledge).', 'You''ll read a METAR before nearly every real flight you ever take — fluency here isn''t optional, it''s a daily-use skill.', false, null, 32),
  ('wx-2', 'weather', 'How is a TAF different from a METAR?', 'A METAR reports current conditions at a specific time; a TAF is a forecast of expected conditions at an airport over a future period (typically 24-30 hours), including expected changes using indicators like BECMG (becoming) and TEMPO (temporary).', 'Treating a TAF as a guarantee rather than a forecast, or missing the significance of a BECMG/TEMPO change group.', 'Whether you understand a TAF''s time-based structure, not just that it''s ''the forecast version of a METAR.''', 'Area of Operation II, Task A — Weather Information (Knowledge).', 'Use the TAF specifically to evaluate your planned arrival time''s forecast conditions — not just the conditions at departure.', false, null, 33),
  ('wx-3', 'weather', 'What is a PIREP, and why is it valuable?', 'A Pilot Report is a real-time, in-flight observation filed by a pilot, giving actual observed conditions (turbulence, icing, cloud tops, visibility) that forecasts alone cannot capture. PIREPs can be filed via radio to Flight Service or ATC.', 'Underweighting PIREPs relative to forecast products, when a recent, relevant PIREP is often more valuable than a general area forecast.', 'Whether you value real, observed data appropriately relative to predictive forecasts.', 'Area of Operation II, Task A — Weather Information (Knowledge).', 'File a PIREP yourself when you encounter significant conditions — you''re both a consumer and a contributor to this system.', false, null, 34),
  ('wx-4', 'weather', 'What is the difference between an AIRMET and a SIGMET?', 'An AIRMET (Airmen''s Meteorological Information) covers weather significant to light aircraft or less experienced pilots — moderate icing, turbulence, or extensive mountain obscuration. A SIGMET covers more severe conditions significant to all aircraft, such as severe turbulence, severe icing, or dust storms; a Convective SIGMET specifically covers thunderstorm-related hazards.', 'Treating AIRMETs as unimportant compared to SIGMETs — for a light, non-icing-certified trainer, an AIRMET Zulu (icing) can be just as flight-critical as a SIGMET.', 'Whether you understand the severity distinction and correctly weigh both categories for your specific aircraft.', 'Area of Operation II, Task A — Weather Information (Knowledge, Risk Management).', 'As a light aircraft pilot, AIRMETs are often more directly relevant to you day-to-day than SIGMETs — don''t skip past them in a briefing.', false, null, 35),
  ('wx-5', 'weather', 'What are the primary hazards associated with thunderstorms?', 'Severe turbulence, downbursts and microbursts, hail, lightning, heavy precipitation reducing visibility, and rapid, unpredictable wind shifts. Thunderstorms progress through cumulus, mature, and dissipating stages, with the mature stage producing the most severe hazards.', 'Focusing only on visible lightning/rain and underestimating the invisible hazards — wind shear and turbulence can extend well beyond the visible storm cell.', 'Whether your mental model of thunderstorm risk includes hazards that extend beyond the storm''s visible boundary.', 'Area of Operation II, Task A — Weather Information (Knowledge, Risk Management).', 'Give any thunderstorm cell wide berth in real flight planning — the rule of thumb of 20 nautical miles exists because these hazards extend well past what you can see.', false, null, 36),
  ('wx-6', 'weather', 'What conditions favor structural icing, and what types exist?', 'Structural icing requires visible moisture and temperatures at or below freezing. Rime ice forms in smaller water droplets/colder conditions and appears rough and opaque; clear ice forms in larger droplets/warmer near-freezing conditions and is smooth, dense, and harder to remove; mixed ice combines both.', 'Believing icing only occurs well below freezing — icing risk is often highest right around the freezing level, not at very cold temperatures.', 'Whether you understand icing as most dangerous near 0°C, not simply ''the colder, the worse.''', 'Area of Operation II, Task A — Weather Information (Knowledge, Risk Management).', 'Most VFR trainers are not certified for flight into known icing — treat any forecast or observed icing as an automatic no-go, not a risk to manage in flight.', false, null, 37),
  ('wx-7', 'weather', 'What are the main types of fog, and how do they form?', 'Radiation fog forms overnight from ground cooling under clear skies and calm wind; advection fog forms when warm, moist air moves over a cooler surface; upslope fog forms as moist air rises and cools along rising terrain. Each has different typical burn-off behavior.', 'Assuming all fog burns off predictably by mid-morning — advection fog in particular can persist much longer than radiation fog.', 'Whether you can identify which fog type applies to a given scenario and reason about its likely persistence.', 'Area of Operation II, Task A — Weather Information (Knowledge, Risk Management).', 'A morning departure delayed by radiation fog often clears within an hour or two after sunrise; the same delay from advection fog might not clear all day — know the difference before you commit to waiting it out.', false, null, 38),
  ('wx-8', 'weather', 'How do you use a winds and temperatures aloft forecast in flight planning?', 'The forecast gives expected wind direction/speed and temperature at specific altitudes and reporting stations, used to select cruising altitude, estimate groundspeed and fuel burn, and check for icing-favorable temperatures at planned altitudes.', 'Only using the forecast for headwind/tailwind planning, and overlooking the temperature data''s relevance to icing risk at altitude.', 'Whether you use this single product for multiple planning purposes — performance and hazard awareness together.', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Knowledge).', 'Choosing a cruising altitude with a favorable tailwind but a freezing temperature and visible moisture is a real, avoidable planning mistake — cross-check both factors together.', false, null, 39),
  ('perf-1', 'performance', 'What is density altitude, and how does it affect performance?', 'Density altitude is pressure altitude corrected for non-standard temperature — it represents the altitude the aircraft ''feels'' it''s performing at. Higher density altitude (hot, high, humid conditions) reduces engine power, propeller efficiency, and lift, increasing takeoff distance and reducing climb performance.', 'Confusing density altitude with pressure altitude, or forgetting that humidity also increases density altitude, not just temperature.', 'Whether you understand density altitude as a performance concept, not just a number to calculate.', 'Area of Operation V, Task A — Performance and Limitations (Knowledge).', 'A hot summer afternoon at a high-elevation airport is exactly when density altitude turns a routine departure into a genuine performance-limited decision.', false, null, 40),
  ('perf-2', 'performance', 'Why does weight and balance matter beyond simply staying under max gross weight?', 'Center of gravity (CG) location affects stall speed, stability, and control authority — an aircraft loaded outside its CG envelope may be uncontrollable even if under max gross weight. Both weight and CG location must be within limits.', 'Checking only total weight against max gross weight and skipping the CG calculation entirely.', 'Whether you treat weight and balance as two distinct checks, both required, not one combined check.', 'Area of Operation V, Task A — Performance and Limitations (Knowledge, Risk Management).', 'A rear-loaded aircraft (aft CG) can become dangerously unstable in pitch — this is a real, not theoretical, loading risk in small trainers with baggage compartments.', false, null, 41),
  ('perf-3', 'performance', 'How does CG location affect stall speed and controllability?', 'A more forward CG generally increases stall speed slightly and improves longitudinal stability; a more aft CG decreases stall speed slightly but reduces stability and can reduce elevator authority, particularly during the flare.', 'Believing CG location has no meaningful effect on stall speed, treating it as purely a stability issue.', 'Detailed understanding connecting CG directly to the aerodynamic concepts (stability, stall speed) tested elsewhere in the oral exam.', 'Area of Operation V, Task A — Performance and Limitations (Knowledge).', 'This is a direct, practical bridge between your weight and balance knowledge and your aerodynamics knowledge — DPEs like connecting these two areas in one question.', false, null, 42),
  ('perf-4', 'performance', 'How do you use a performance chart correctly, including interpolation?', 'Enter the chart with the actual conditions (pressure altitude, temperature, weight, wind), and if your exact values fall between published data points, interpolate between the two nearest values rather than simply rounding to the nearest chart line.', 'Always rounding to the nearest (and often more favorable) chart value instead of interpolating, which can understate actual required distance.', 'Whether you interpolate correctly and conservatively, since misreading a performance chart has real safety consequences.', 'Area of Operation V, Task A — Performance and Limitations (Skill, Knowledge).', 'Practice interpolating on your specific aircraft''s real performance charts with realistic numbers — this is often demonstrated live during the oral exam, not just discussed.', false, null, 43),
  ('perf-5', 'performance', 'What factors increase takeoff distance?', 'High density altitude, higher aircraft weight, a tailwind component, an uphill or soft/contaminated runway surface, and reduced flap settings (below the optimal takeoff setting) all increase required takeoff distance.', 'Naming only density altitude and weight, forgetting runway surface, slope, and wind component factors.', 'Whether you can name a comprehensive list of factors, not just the two most commonly cited.', 'Area of Operation V, Task A — Performance and Limitations (Knowledge, Risk Management).', 'Combine factors mentally before every real departure — hot day, uphill runway, and a slight tailwind together compound quickly into a genuine performance problem.', false, null, 44),
  ('perf-6', 'performance', 'What factors increase landing distance?', 'High density altitude, higher aircraft weight, a tailwind component, a wet, contaminated, or downhill runway, and excess airspeed over the threshold all increase required landing distance.', 'Forgetting excess approach speed as a factor — landing fast, even briefly, meaningfully extends the landing roll.', 'Whether your factor list matches the takeoff list''s logic while correctly noting landing-specific factors like approach speed discipline.', 'Area of Operation V, Task A — Performance and Limitations (Knowledge, Risk Management).', 'Approach speed discipline is one of the most controllable variables on this entire list — flying the correct speed on final directly manages your landing distance risk.', false, null, 45),
  ('perf-7', 'performance', 'How does wind component affect takeoff and landing performance?', 'A headwind component reduces ground roll and required distance; a tailwind component significantly increases required distance — tailwind effects are disproportionately larger than headwind benefits for the same wind speed, so even a small tailwind matters.', 'Treating headwind and tailwind effects as symmetrical, when tailwind penalties are actually more severe for the same speed.', 'Whether you understand this asymmetry, which is a commonly tested nuance beyond the basic headwind/tailwind concept.', 'Area of Operation V, Task A — Performance and Limitations (Knowledge).', 'Always calculate actual crosswind and headwind/tailwind components before a flight rather than eyeballing the windsock — the numbers matter more than they look.', false, null, 46),
  ('perf-8', 'performance', 'How does CG shift as fuel burns off during a flight?', 'As fuel burns, weight decreases, and CG typically shifts based on where the fuel tanks are located relative to the CG — in most training aircraft with wing tanks near the CG, this shift is minor, but it should still be checked for flights near a CG limit.', 'Assuming CG never meaningfully changes in flight, when a flight loaded near a limit at departure could shift outside limits by the end of a long flight.', 'Whether you think about weight and balance as a full-flight consideration, not just a departure-moment calculation.', 'Area of Operation V, Task A — Performance and Limitations (Knowledge, Risk Management).', 'For any flight loaded close to a CG limit, calculate both a takeoff and a landing weight and balance — don''t assume the departure check is sufficient for the whole flight.', false, null, 47),
  ('aeromed-1', 'aeromedical', 'What is hypoxia, and what are its stages and symptoms?', 'Hypoxia is a deficiency of oxygen reaching body tissues. Symptoms progress from mild impairment (poor judgment, euphoria) to more severe cognitive and physical impairment as altitude or exposure increases, and can occur even below 10,000 feet MSL in susceptible individuals (smokers, fatigue, illness).', 'Believing hypoxia only becomes a concern at very high altitudes, ignoring individual susceptibility factors.', 'Whether you understand hypoxia risk as altitude-dependent but also individually variable, not a single fixed threshold.', 'Area of Operation VII, Task A — Aeromedical Factors (Knowledge).', 'Supplemental oxygen use, or simply descending, are your practical tools here — know your own personal risk factors, not just the general altitude guidance.', false, null, 48),
  ('aeromed-2', 'aeromedical', 'How is hyperventilation different from hypoxia, and how do you tell them apart?', 'Hyperventilation is excessive breathing rate, often triggered by stress or anxiety, causing symptoms (dizziness, tingling, lightheadedness) that closely mimic hypoxia. The key distinguishing action is deliberately slowing your breathing rate — if symptoms improve, it was hyperventilation; if not, treat it as hypoxia and take corrective action (oxygen, descent).', 'Assuming any dizziness in flight is automatically anxiety-related without also considering hypoxia as a possibility, especially at altitude.', 'Whether you have an actual decision process for distinguishing these two conditions in the moment, not just definitions of each.', 'Area of Operation VII, Task A — Aeromedical Factors (Knowledge, Risk Management).', 'This is a genuinely useful in-flight decision tool — know the actual test (controlled breathing) you''d perform, not just the textbook definitions.', false, null, 49),
  ('aeromed-3', 'aeromedical', 'What are common spatial disorientation illusions, and how do you prevent them?', 'Illusions include the leans, the graveyard spiral, and somatogravic illusion, among others — all caused by the inner ear and other senses providing false orientation information, especially in reduced visibility. Prevention relies on trusting flight instruments over physical sensation when visual references are limited.', 'Believing spatial disorientation only affects instrument-rated pilots in IMC — it can occur in degraded visual conditions (haze, night, featureless terrain) that a VFR-only pilot may encounter.', 'Whether you understand the practical prevention strategy (trust instruments), not just illusion names.', 'Area of Operation VII, Task A — Aeromedical Factors (Knowledge, Risk Management).', 'This is why VFR-into-IMC is so dangerous even for skilled visual pilots — your body will lie to you convincingly, and only instrument trust reliably counters it.', false, null, 50),
  ('aeromed-4', 'aeromedical', 'What does the IMSAFE checklist stand for, and how do you use it?', 'Illness, Medication, Stress, Alcohol, Fatigue, Emotion — a personal fitness-to-fly self-assessment performed before every flight, honestly evaluating each factor.', 'Treating IMSAFE as a one-time or occasional check rather than a habitual pre-flight self-assessment for every single flight.', 'Whether this is a genuine, internalized habit for you, not just a memorized acronym.', 'Area of Operation VII, Task A — Aeromedical Factors (Knowledge, Risk Management).', 'Be ready to apply IMSAFE honestly to yourself, out loud, on checkride day — examiners sometimes ask directly, and a thoughtful real answer lands far better than a rushed recitation.', false, null, 51),
  ('aeromed-5', 'aeromedical', 'What are the FAA''s regulations regarding alcohol and flying?', 'You may not act as a crewmember within 8 hours of consuming alcohol, while under the influence of alcohol, or with a blood alcohol concentration of 0.04% or greater; some operators and the FAA also apply a stricter 24-hour guideline as best practice.', 'Citing only the ''8 hours'' rule and forgetting the BAC limit and ''under the influence'' standard, which can apply even beyond 8 hours.', 'Whether you know all three components of this regulation, not just the most commonly cited one.', 'Area of Operation VII, Task A — Aeromedical Factors (Knowledge).', 'Apply the stricter, safer standard in your own personal minimums — the legal minimum and the genuinely safe minimum are not always the same number.', false, null, 52),
  ('aeromed-6', 'aeromedical', 'How does fatigue affect pilot performance, and how do you recognize it in yourself?', 'Fatigue degrades reaction time, judgment, attention, and decision-making, often without the pilot feeling overtly ''tired'' — chronic fatigue from poor sleep patterns can be just as impairing as acute fatigue from a long, demanding day.', 'Believing fatigue only matters after an obviously exhausting day, missing the risk of cumulative, chronic fatigue from ordinary life stress or poor sleep habits.', 'Whether you recognize fatigue as a real IMSAFE factor deserving honest self-assessment, not something you''d only notice if extreme.', 'Area of Operation VII, Task A — Aeromedical Factors (Knowledge, Risk Management).', 'Track your own sleep before flight lessons and notice the honest correlation with your performance — this builds real self-awareness, not just textbook knowledge.', false, null, 53),
  ('aeromed-7', 'aeromedical', 'What are the sources and symptoms of carbon monoxide poisoning in a piston aircraft?', 'CO can enter the cabin through a cracked or faulty exhaust/heater muff system, especially with cabin heat in use. Symptoms include headache, dizziness, confusion, and drowsiness — easily mistaken for fatigue or hypoxia, making it especially dangerous.', 'Assuming CO poisoning would be obviously noticeable, when its symptoms actually mimic other, less dangerous-sounding conditions.', 'Whether you know both the mechanical source and the deceptive symptom overlap with other aeromedical conditions.', 'Area of Operation VII, Task A — Aeromedical Factors (Knowledge, Risk Management).', 'A cheap CO detector in the cabin is a genuinely worthwhile investment for any pilot flying an aircraft with a heater muff system, especially in winter.', false, null, 54),
  ('aeromed-8', 'aeromedical', 'Why is honest self-assessment more important than technical knowledge in this section?', 'Aeromedical risks are the ones a pilot is uniquely positioned to catch — no checklist, chart, or ATC controller will notice your fatigue or stress level for you. This section of the ACS specifically tests whether you''ll apply that self-awareness honestly, not just whether you can define the terms.', 'Answering aeromedical questions purely academically, without connecting them to genuine, personal self-assessment habits.', 'Maturity and honesty about your own limitations — this is arguably the most personal, judgment-based ACS content on the entire exam.', 'Area of Operation VII, Task A — Aeromedical Factors (Risk Management).', 'The pilots who fly safely for decades are the ones who keep applying IMSAFE honestly at hour 5,000, not just during training — build the habit now.', false, null, 55),
  ('xc-1', 'crosscountry', 'What are the essential components of a complete cross-country flight plan?', 'A navigation log (course, heading, groundspeed, ETE, and fuel per leg), a weather briefing, a weight and balance calculation, a performance calculation for departure and destination, and selected cruising altitude(s) based on terrain, airspace, and direction of flight.', 'Treating the nav log alone as ''the flight plan,'' when a complete plan integrates weather, performance, and weight and balance together.', 'Whether you understand cross-country planning as an integration of multiple ACS knowledge areas, not an isolated task.', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Knowledge, Skill).', 'Bring a complete, real plan for an actual route to your checkride — expect to walk through it in detail as a central part of the oral exam.', false, null, 56),
  ('xc-2', 'crosscountry', 'What are the VFR fuel reserve requirements for day and night flight?', 'For day VFR, you must have enough fuel to fly to the first point of intended landing and then, at normal cruising speed, fly for an additional 30 minutes. For night VFR, that reserve increases to 45 minutes.', 'Applying the day reserve requirement to a flight that will arrive after dark, or forgetting the reserve applies at normal cruising speed, not an economy setting.', 'Whether you correctly apply day versus night reserve based on actual arrival conditions, not just departure time.', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Knowledge, Risk Management).', 'Plan reserves generously beyond the legal minimum on real flights — the legal reserve is a floor, not a target.', false, null, 57),
  ('xc-3', 'crosscountry', 'What is your process for diverting to an alternate airport in flight?', 'Identify the nearest suitable airport given current position, fuel, and weather; establish a heading and rough distance/time using pilotage or your EFB; communicate your intentions if appropriate; and continuously reassess as conditions develop.', 'Overcomplicating the process by trying to build a perfect new nav log in flight, rather than using a quick, practical heading-and-distance estimate.', 'Whether you have a genuinely practical, fast process for a real in-flight decision, not just a textbook answer.', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Skill, Risk Management).', 'Practice this exact skill — picking a real diversion airport mid-flight and estimating heading/time — with your instructor before your checkride, since it''s often demonstrated live.', true, 8, 58),
  ('xc-4', 'crosscountry', 'What are the ''four C''s'' of lost procedures?', 'Climb (for a better view and radio/GPS reception), Communicate (contact ATC or Flight Service for help), Confess (state clearly that you''re unsure of your position), and Comply (follow the guidance you''re given).', 'Being reluctant to actually ''confess'' being lost, when clear communication of the situation is what allows ATC to help effectively and quickly.', 'Whether you''d actually use this process in the moment, including the psychologically harder step of clearly stating you''re lost.', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Knowledge, Risk Management).', 'There''s no professional downside to admitting uncertainty to ATC — controllers deal with this constantly and are there to help, not to judge.', true, 9, 59),
  ('xc-5', 'crosscountry', 'What is the difference between pilotage and dead reckoning?', 'Pilotage is navigation by visually referencing landmarks against a chart; dead reckoning is navigation by calculating heading, groundspeed, and time based on planned course and forecast wind, without relying on visual checkpoints alone.', 'Treating these as mutually exclusive rather than complementary techniques typically used together on a real cross-country flight.', 'Whether you understand these as a combined skill set, not an either/or choice.', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Knowledge, Skill).', 'These are your backup navigation skills if GPS or electronics fail — practice them for real, not just as a theoretical checkride topic.', false, null, 60),
  ('xc-6', 'crosscountry', 'How do you use a VOR for navigation, and how do you verify its accuracy?', 'Tune and identify the station via Morse code, center the CDI needle, and read the radial you''re on or flying to/from using the TO/FROM indicator. VOR accuracy can be verified using a VOT test, a certified ground checkpoint, or a certified airborne checkpoint, generally within a specified tolerance.', 'Skipping station identification, or being unfamiliar with any of the three accuracy-check methods.', 'Whether you can both operate a VOR practically and explain how its accuracy is verified — a two-part skill many applicants only prepare half of.', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Knowledge, Skill).', 'Even in a GPS-heavy cockpit, VOR remains a valuable backup — stay genuinely proficient, not just checkride-ready.', false, null, 61),
  ('xc-7', 'crosscountry', 'How do you select an appropriate cruising altitude for a cross-country flight?', 'Apply the hemispheric rule (odd thousands + 500 feet for VFR flight on courses roughly 0-179° magnetic, even thousands + 500 feet for 180-359°), while also considering terrain clearance, airspace structure, and winds aloft.', 'Applying the hemispheric rule mechanically without also checking it against terrain and airspace — the ''legal'' altitude and the ''safe and practical'' altitude must both be satisfied.', 'Whether you integrate the regulatory rule with real terrain and airspace judgment, not just recite the altitude formula.', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Knowledge, Risk Management).', 'In mountainous terrain especially, the hemispheric-rule altitude and the genuinely safe altitude can differ significantly — always cross-check both.', false, null, 62),
  ('xc-8', 'crosscountry', 'How do you file, activate, and close a VFR flight plan, and why does it matter?', 'File via Flight Service (1800wxbrief.com, phone, or many EFBs), activate it once airborne (it doesn''t activate automatically), and close it upon landing, either by radio or phone — an unclosed flight plan triggers search-and-rescue procedures.', 'Forgetting the flight plan must be manually activated after filing, or forgetting to close it after landing, which triggers unnecessary search-and-rescue resources.', 'Whether you understand this as a full three-step process (file, activate, close), not just the filing step alone.', 'Area of Operation IX, Task A — Navigation Systems and Flight Planning (Knowledge, Risk Management).', 'A VFR flight plan isn''t required, but it''s genuinely good practice — it''s the system that gets search-and-rescue looking for you quickly if something goes wrong.', false, null, 63),
  ('emerg-1', 'emergency', 'What is your procedure for an engine failure immediately after takeoff?', 'Establish best glide (or the appropriate pitch attitude), land essentially straight ahead within a narrow range of turn, and avoid attempting to turn back to the runway at low altitude unless you have specifically trained for and are confident in that maneuver at sufficient altitude.', 'Defaulting to ''turn back to the runway'' as a general answer without acknowledging the significant altitude and airspeed risk this maneuver carries at low altitude — the so-called ''impossible turn.''', 'Whether your default response prioritizes a safe, controlled landing over an instinctive but risky return to the runway.', 'Area of Operation X, Task A — Emergency Procedures (Knowledge, Risk Management, Skill).', 'Discuss your specific aircraft''s and airport''s numbers with your instructor — the altitude at which a return-to-field turn becomes reasonable is aircraft- and situation-specific, not a universal rule.', true, 0, 64),
  ('emerg-2', 'emergency', 'What is your procedure for an engine failure in flight, away from the airport?', 'Establish best glide speed immediately, select a suitable landing field within gliding distance, run through the appropriate engine restart checklist if time and altitude allow, communicate your situation (squawk 7700, radio call) if able, and prepare the cabin and passengers for landing.', 'Attempting an engine restart checklist before first establishing best glide and a landing site — the sequence matters, and aviate always comes before troubleshoot.', 'Whether you can state this procedure in the correct priority order, not just list the individual steps.', 'Area of Operation X, Task A — Emergency Procedures (Knowledge, Risk Management, Skill).', 'Memorize your specific aircraft''s best glide speed and emergency checklist — this is exactly the kind of information that must be instantly available, not looked up.', true, 1, 65),
  ('emerg-3', 'emergency', 'What are the signs of an alternator failure, and what is your response?', 'A low-voltage or alternator warning light/annunciator, and a battery ammeter showing discharge rather than charge. Response includes reducing electrical load (turning off non-essential equipment), checking circuit breakers, and monitoring battery voltage to preserve remaining electrical endurance for essential equipment.', 'Confusing an alternator failure with a complete electrical failure — with an alternator failure, the battery still provides limited remaining power, which should be conserved, not immediately abandoned.', 'Whether you understand this as a manageable, time-limited situation requiring load-shedding, not an immediate full emergency.', 'Area of Operation X, Task A — Emergency Procedures (Knowledge, Risk Management).', 'Know which equipment in your specific aircraft draws the most electrical load, so you can prioritize shedding it first in a real alternator failure.', true, 2, 66),
  ('emerg-4', 'emergency', 'What is the PIC''s emergency authority under 14 CFR 91.3(b)?', 'In an in-flight emergency requiring immediate action, the pilot in command may deviate from any rule in Part 91 to the extent required to meet that emergency, and may be required to submit a written report of that deviation if requested by the FAA.', 'Believing this authority is unlimited or requires no follow-up, when a written report may still be required after the fact.', 'Whether you understand both the authority and the accountability that follows it.', 'Area of Operation X, Task A — Emergency Procedures (Knowledge).', 'This regulation exists so that, in a genuine emergency, you make the safest decision without hesitating over regulatory compliance — use it if you ever truly need it, and document afterward.', true, 7, 67),
  ('emerg-5', 'emergency', 'What system malfunction indications should you recognize for a vacuum system failure?', 'A vacuum failure typically shows as a flag or visible failure on the attitude indicator and/or heading indicator (the gyroscopic instruments driven by the vacuum system), while the airspeed indicator, altimeter, and VSI (pitot-static instruments) remain unaffected.', 'Not knowing which specific instruments are vacuum-driven versus electrically or pitot-static driven in your specific aircraft''s panel configuration.', 'Whether you know your own aircraft''s specific instrument power sources, not just a generic answer.', 'Area of Operation X, Task A — Emergency Procedures (Knowledge, Risk Management).', 'In a vacuum failure, cross-check your remaining reliable instruments (airspeed, altimeter, turn coordinator if electric) rather than trusting a failed attitude indicator.', true, 3, 68),
  ('emerg-6', 'emergency', 'What is the procedure for an emergency descent?', 'Reduce power, establish the appropriate descent configuration and airspeed per your aircraft''s emergency procedures (often including a specific bank angle to increase descent rate while managing structural limits), and communicate your intentions if able.', 'Not knowing your specific aircraft''s published emergency descent procedure and airspeed, relying instead on a generic ''dive steeply'' assumption.', 'Aircraft-specific procedural knowledge, not just a general concept of descending quickly.', 'Area of Operation X, Task A — Emergency Procedures (Knowledge, Skill).', 'Review your specific POH''s emergency descent procedure — the correct technique balances speed of descent against structural and control limits.', true, 4, 69),
  ('emerg-7', 'emergency', 'What is the procedure for lost communications?', 'Squawk 7600 to alert ATC of the radio failure, continue navigating per your last clearance or filed plan, and if in controlled airspace requiring communication, use light gun signals if near a tower, or proceed according to standard lost-comm procedures for the type of operation.', 'Forgetting to squawk 7600, or being unfamiliar with basic light gun signal meanings for arrival at a towered airport.', 'Whether you have a genuinely usable, memorized procedure for this specific and realistic failure mode.', 'Area of Operation X, Task A — Emergency Procedures (Knowledge).', 'Review light gun signals specifically before your checkride — this is a commonly tested, easy-to-forget detail since most pilots never actually experience it.', true, 5, 70),
  ('emerg-8', 'emergency', 'What are your basic reporting responsibilities after an aircraft accident or incident?', 'Certain accidents and serious incidents must be reported to the NTSB as soon as practicable, and specific wreckage/records preservation requirements apply following a reportable accident, per NTSB Part 830.', 'Believing all incidents require NTSB notification, when the reporting threshold is specifically defined and not every abnormal event qualifies.', 'Basic awareness that this reporting framework exists, even if full regulatory detail isn''t expected at the private pilot level.', 'Area of Operation X, Task A — Emergency Procedures (Knowledge).', 'Know that this requirement exists before you ever need it — in the unlikely event of a reportable incident, knowing your basic obligations reduces additional stress at an already difficult time.', true, 6, 71);

insert into public.quick_reference_sheets (id, title, subtitle, rows, sort_order) values
  ('qr-arrow', 'ARROW', 'Required aircraft documents', '[["A","Airworthiness Certificate","Must be displayed in the aircraft, visible to passengers/occupants."],["R","Registration","Current FAA registration certificate."],["R","Radio Station License","Generally not required for domestic U.S. operations; required for certain international flights."],["O","Operating Limitations","POH/AFM, placards, or markings — whichever applies to the aircraft."],["W","Weight and Balance Data","Current weight and balance report and equipment list."]]'::jsonb, 0),
  ('qr-tomato', 'A TOMATO FLAMES', 'Required equipment for day VFR flight — 14 CFR 91.205(b)', '[["A","Airspeed Indicator",""],["T","Tachometer (for each engine)",""],["O","Oil Pressure Gauge","For each engine using a pressure system."],["M","Manifold Pressure Gauge","For each altitude engine (controllable pitch prop)."],["A","Altimeter",""],["T","Temperature Gauge","For each liquid-cooled engine."],["O","Oil Temperature Gauge","For each air-cooled engine."],["F","Fuel Gauge","Indicating quantity in each tank."],["L","Landing Gear Position Indicator","If retractable gear."],["A","Anti-Collision Lights","For aircraft certificated after March 11, 1996."],["M","Magnetic Compass",""],["E","ELT","Emergency Locator Transmitter, per 91.207."],["S","Seat Belts (and shoulder harnesses)","As required per occupant/seat."]]'::jsonb, 1),
  ('qr-av1ates', 'AV1ATES', 'Recurring aircraft inspections that keep it legal for flight', '[["A","Annual","Required every 12 calendar months, performed by an A&P mechanic holding an Inspection Authorization (IA)."],["V","VOR Check","Required every 30 days if the aircraft is flown IFR under VOR navigation."],["1","100-Hour","Required if the aircraft is used for hire or for flight instruction for hire."],["A","Alt/Static System","Altimeter and static system check, required every 24 calendar months for IFR operations."],["T","Transponder","Required every 24 calendar months."],["E·S","ELT Inspections","Required every 12 calendar months, with battery replacement per manufacturer requirements or after one hour of cumulative use."]]'::jsonb, 2),
  ('qr-imsafe', 'IMSAFE', 'Personal fitness-to-fly self-assessment', '[["I","Illness","Any symptoms that could affect performance, even minor."],["M","Medication","Prescription, over-the-counter, and their side effects."],["S","Stress","Personal, professional, or checkride-related stress."],["A","Alcohol","Apply the 8-hour/24-hour/BAC standard."],["F","Fatigue","Both acute (last night''s sleep) and chronic (sleep pattern over weeks)."],["E","Emotion","Emotional state and its effect on judgment and focus."]]'::jsonb, 3),
  ('qr-pave', 'PAVE', 'Risk management framework for every flight', '[["P","Pilot","Your own currency, proficiency, and IMSAFE status."],["A","Aircraft","Airworthiness, performance, and equipment for the planned flight."],["V","enVironment","Weather, airspace, terrain, and airport conditions."],["E","External Pressures","Schedule, passengers, cost, or ego-driven pressure to fly."]]'::jsonb, 4),
  ('qr-care', 'CARE', 'Risk-factor identification model (used alongside TEAM)', '[["C","Consequences","What''s actually at stake if this risk materializes?"],["A","Alternatives","What other options exist besides the current plan?"],["R","Reality","Is your assessment of the situation actually accurate?"],["E","External Factors","What outside pressures might be distorting your judgment?"]]'::jsonb, 5),
  ('qr-nwkraft', 'NWKRAFT', 'Preflight and cross-country briefing checklist', '[["N","NOTAMs","Check for current NOTAMs affecting your route, departure, and destination."],["W","Weather","Full briefing — current conditions, forecasts, and any AIRMETs/SIGMETs along your route."],["K","Known ATC Delays","Check for published ground stops, delays, or routing advisories."],["R","Runway Lengths","Confirm available runway length at departure, destination, and any planned alternate."],["A","Alternates","Identify suitable alternate airports along your route in case of a diversion."],["F","Fuel Requirements","Calculate total fuel required including the appropriate day/night VFR reserve."],["T","Takeoff and Landing Distances","Calculate actual performance-based distances for the day''s conditions, not just legal minimums."]]'::jsonb, 6);

insert into public.portal_lessons (id, title, meta, parts, sort_order) values
  ('lesson-framework', 'Checkride Success Framework', 'Section 1 · How the oral exam actually works', '[{"h":"Welcome Letter from Apex Aviation","body":["Welcome to the Apex Advantage Private Pilot Checkride Prep Pack — and congratulations on making it this far. If you''re holding this guide, you''ve already put in the real work: the flight hours, the ground school, the long study nights. What you''re looking for now isn''t more information. It''s confidence — the kind that comes from knowing exactly what to expect and exactly how to show up prepared.","We built this guide the way we build every part of Apex Advantage: around a simple idea we call Train Beyond the Checkride. The oral exam isn''t a memorization contest, and your examiner isn''t trying to trip you up. A Designated Pilot Examiner is trying to find out one thing — are you the kind of pilot who can be trusted to make good decisions alone in an airplane? Every question in this guide is built to help you answer that question with real, durable understanding, not a script.","This isn''t a textbook, and it isn''t a cram sheet. It''s a study partner — the same kind of structured, scenario-based preparation our live students get in Apex Advantage ground school, distilled into a guide you can work through at your own pace. Use it well, and you won''t just pass your checkride. You''ll walk into it calm, because you''ll already know you''re ready.","Fly safe, study well, and welcome to Apex. — The Apex Aviation Team"]},{"h":"How to Use This Guide","list":["Work section by section, in order — the sections roughly follow the structure of a real oral exam, building from documents and regulations toward judgment and real-world scenarios.","Don''t just read the Model Answer — cover it, answer the question out loud in your own words first, then compare. Speaking your answer is what actually builds checkride-ready recall.","Pay close attention to the Common Student Mistakes field for every question — these are the specific, predictable ways applicants lose confidence points, and knowing them in advance is half the battle.","Use the ACS Connection field to cross-reference the current Airman Certification Standards directly — this guide is a companion to the ACS, not a replacement for reading it.","Keep the Quick Reference Appendix close during your final week of study — it''s built for fast review, not first-time learning.","If a question or concept still feels shaky after working through this guide, that''s useful information — bring it to your CFI directly rather than letting it go unresolved into checkride day."]},{"h":"Understanding the FAA ACS","body":["The Airman Certification Standards (ACS) is the actual rubric your DPE uses to evaluate you — not a general guideline, the specific, official standard. Every checkride question you''ll ever be asked traces back to a specific Area of Operation and Task within the ACS.","The ACS structure has three layers, and understanding this structure is itself checkride-relevant knowledge:"],"list":["Areas of Operation — the broad phases of flight and knowledge domains (e.g., Preflight Preparation, Airspace, Slow Flight and Stalls).","Tasks — specific, named skills or knowledge sets within each Area of Operation (e.g., Task B: Airworthiness Requirements).","Elements — every Task breaks down into Knowledge, Risk Management, and Skill elements. This three-part structure is what distinguishes the modern ACS from the older Practical Test Standards (PTS): risk management is now explicitly, separately evaluated, not folded into a general skill assessment."],"tip":{"label":"Instructor Tip — Read the ACS Yourself","body":"This guide maps every question to its ACS reference on purpose — use that reference to go read the actual ACS language for that Task. A DPE is quoting from that exact document, and familiarity with its actual phrasing will make you sound like you know the standard, not just the topic."}},{"h":"How Oral Exams Are Evaluated","body":["The oral exam is not a test of whether you can recite facts — it''s a structured, scenario-based conversation designed to reveal how you think. A DPE will typically open with a real or realistic scenario (a planned flight, a specific airport, a specific day''s weather) and ask you to reason through it, weaving in regulatory and technical questions naturally as the scenario unfolds.","Within each ACS Task, your examiner is listening for three things: Knowledge (do you know the correct information), Risk Management (can you identify and mitigate the relevant risks), and Skill (where applicable, can you demonstrate the associated physical or procedural skill, generally during the flight portion). A complete answer touches Knowledge and, where relevant, Risk Management — an answer that''s only a fact recitation is often incomplete by ACS standards, even if factually correct.","Examiners are also evaluating your process, not just your final answer: do you know where to look something up if you''re not sure? Do you stay calm and structured when you don''t immediately know an answer? Composure under a moment of uncertainty is itself part of what''s being evaluated — a hesitant but structured ''let me check that'' response often scores better than a fast, confidently wrong one."]},{"h":"What DPEs Are Looking For","list":["Genuine understanding over memorization — an examiner will almost always ask a ''why'' or ''what if'' follow-up to any definitional answer, specifically to test whether you understand the concept or just memorized a sentence.","Accurate use of current references — knowing how to find an answer in the FAR/AIM, POH, or a chart, live, is treated as equally valuable to knowing the answer from memory.","Sound aeronautical decision-making — your reasoning process when weighing a real risk (weather, performance, personal minimums) matters as much as the specific decision you land on.","Professional communication — clear, organized, confident answers, delivered the way you''d actually brief a passenger or communicate with ATC.","Honest self-assessment — examiners respond far better to ''I''m not certain, let me look that up,'' than to guessing or bluffing."]},{"h":"Common Reasons Applicants Fail","table":{"headers":["Common Failure Pattern","What''s Actually Happening"],"rows":[["Memorized answers that fall apart under a follow-up question","The applicant learned a sentence, not the underlying concept — the first ''why'' question exposes the gap."],["Treating the oral exam like a pop quiz instead of a conversation","Answering in isolated fragments instead of reasoning through the scenario the examiner is building."],["Guessing instead of saying ''I don''t know, let me check''","Examiners consistently rate honest uncertainty higher than a confident wrong answer — guessing erodes trust fast."],["Incomplete knowledge of personal documents and currency","Basic eligibility gaps (expired medical, missing endorsement) are avoidable, low-effort failure points that undermine an otherwise strong exam."],["Underprepared risk management reasoning","Applicants who can recite regulations but can''t apply a framework like PAVE or IMSAFE to a real scenario struggle with the ACS''s Risk Management elements specifically."],["Visible panic or shutting down under pressure","A single missed question is recoverable; losing composure and disengaging from the conversation is what actually derails an oral exam."]]},"tip":{"label":"Checkride Success Tip — The Real Fix","body":"Every failure pattern above has the same root fix: work through real questions out loud, under mild time pressure, before checkride day — exactly what this guide and Apex Advantage''s live Checkride Corner training are built to do."}}]'::jsonb, 0),
  ('lesson-checkride-day', 'Checkride Day Preparation', 'Section 11 · Documents, timing, and composure', '[{"h":"Overview","body":["Everything in this section is about removing avoidable friction from checkride day, so your energy goes entirely toward the exam itself — not toward finding a missing document or managing unnecessary stress."]},{"h":"What to Bring","list":["Government-issued photo ID","Student pilot certificate / medical certificate","Completed and signed IACRA application (Form 8710-1)","Logbook with all required endorsements","Knowledge Test Report","Aircraft airworthiness certificate, registration, operating limitations, and weight and balance data (ARROW)","Aircraft maintenance logs (or evidence of required inspections)","Current charts, plotter, E6B (electronic or manual), and your completed cross-country flight plan","Examiner''s fee, in the payment method they specify in advance"]},{"h":"Day-Before Checklist","list":["Confirm weather and NOTAMs for your planned checkride route one more time","Verify every document above is physically gathered in one place, not scattered","Review your cross-country flight plan and be ready to explain every number in it","Get a full night''s sleep — treat this as seriously as you would before a flight lesson","Avoid last-minute cramming on brand-new material; focus instead on your weakest, already-identified areas"]},{"h":"Morning-Of Checklist","list":["Eat a real meal — low blood sugar undermines focus exactly when you need it most","Arrive early, not just on time, to avoid any rushed, stressed start","Do a final honest IMSAFE check on yourself","Review your Quick Reference sheets one final time, calmly — not as new learning, just as a confidence check","Remind yourself: your instructor endorsed you because they believe you''re ready. Trust that assessment."]},{"h":"Common Mistakes on Checkride Day","list":["Arriving with incomplete paperwork, which can delay or cancel the exam entirely","Trying to learn new material the morning of, instead of reinforcing what''s already solid","Guessing confidently instead of saying ''I''m not sure, let me check'' when appropriate","Letting one missed question derail composure for the rest of the exam","Underestimating the professionalism component — how you communicate matters, not just what you know"]},{"h":"Professionalism Tips","list":["Dress and present yourself the way you would for a professional interview — this sets a tone before you say a word.","Treat the DPE as a respected colleague evaluating your readiness, not an adversary trying to catch you out — because that''s genuinely their role.","Speak in complete, organized answers rather than fragments — structure your response the way you''d brief a passenger.","If you don''t know something, say so clearly and show how you''d find the answer — this is a strength, not a weakness, in a DPE''s eyes."]},{"h":"Stress Management Techniques","list":["Box breathing (inhale 4 seconds, hold 4, exhale 4, hold 4) before and during the exam if you feel your nerves spike — a genuinely effective, discreet technique.","Reframe the oral exam as a conversation with a fellow aviator, not an interrogation — because that''s structurally closer to what it actually is.","If you blank on a question, pause, breathe, and restate the question back in your own words — this buys real thinking time without appearing evasive.","Remember that a single missed question is recoverable — examiners expect some hesitation and imperfection, and are evaluating your overall judgment, not a flawless performance."],"tip":{"label":"Checkride Success Tip — You Are More Ready Than You Feel","body":"Checkride anxiety is nearly universal, even among applicants who are genuinely well-prepared. Your instructor''s endorsement means they believe, professionally, that you''re ready — let that carry some of the weight on exam morning."}}]'::jsonb, 1);
